package mk.ukim.finki.ds;
import java.util.HashMap;
import java.util.Map;

class LetterSubstitution {

     private static Map<Character, Character> getCharacterCharacterMap() {
         Map<Character, Character> mappings = new HashMap<>();
         mappings.put('А', 'Ж');
         mappings.put('Б', 'Н');
         mappings.put('В', 'Т');
         mappings.put('Г', 'К');
         mappings.put('Д', 'Ш');
         mappings.put('Ѓ', 'А');
         mappings.put('Е', 'Љ');
         mappings.put('Ж', 'Ф');
         mappings.put('З', 'Д');
         mappings.put('Ѕ', 'Ќ');
         mappings.put('И', 'Р');
         mappings.put('Ј', 'С');
         mappings.put('К', 'Г');
         mappings.put('Л', 'Ц');
         mappings.put('Љ', 'В');
         mappings.put('М', 'П');
         mappings.put('Н', 'Е');
         mappings.put('Њ', 'Ч');
         mappings.put('О', 'Ј');
         mappings.put('П', 'М');
         mappings.put('Р', 'О');
         mappings.put('С', 'Ѕ');
         mappings.put('Т', 'З');
         mappings.put('Ќ', 'У');
         mappings.put('У', 'Б');
         mappings.put('Ф', 'Ѓ');
         mappings.put('Х', 'Л');
         mappings.put('Ц', 'Х');
         mappings.put('Ч', 'Њ');
         mappings.put('Џ', 'Џ');
         mappings.put('Ш', 'И');
         return mappings;
     }

     public static String substituteLetters(String text, Map<Character, Character> mappings) {
         StringBuilder result = new StringBuilder();

         for (char c : text.toCharArray()) {
             result.append(mappings.getOrDefault(c, c));
         }

         return result.toString();
     }

     public static void main(String[] args) {
         Map<Character, Character> mappings = getCharacterCharacterMap();

         String original = "На крајот од јануари заврши рокот за аплицирање на тендерот распишан од Министерството за образование и наука кон крајот на 2025 врз основа на стручната анализа за состојбата во која се сега недоградените објекти и согласно потребите на нивните идни корисници. Во јуни 2025 година беше формирана работна група составена од претставници на сите засегнати факултети при УКИМ - Градежен, Машински, МОН и СОЗР, која ќе ги отстранува пречките за да продолжи изградбата на двата објекта во дворот на УКИМ. Работната група која ја координира проф. д-р Горан Марковски од Градежниот факултет (до неодамна декан на факултетот) иницира ревизија на постојните проекти за изградба, поради во меѓувреме наметнати нови стандарди за градба, опремување и слично, како и заради намалување на трошоците со отстранување на одредени позиции кои нема да влијаат врз функционалноста - рекоа од МОН за Факултети.мк. Во моментов тече евалуацијата на понудите во МОН и откако ќе заврши постапката и доградбата на објектите ќе биде репроектирана, ќе се избере и изведувач на градежните работи. Беше извршена анализа на карабините, имајќи предвид дека изградбата повеќе години беше во застој, поточно од 2019 година, по што се објави постапка за јавна набавка за репроектирање. Пристигнати се 7 понуди и во моментов во тек е евалуација на понудите. Откако ќе заврши постапката и доградбата на објектите ќе биде репроектирана, ќе се спроведе и постапка за избор на изведувач на градежните работи. Според процените, за двата објекта во дворот на УКИМ ќе бидат потребни по околу 15 милиони евра за да бидат целосно завршени и ќе ги користи само ФИНКИ - велат од МОН. Од Министерството објаснија дека за Факултетот за физичка култура, спорт и здравје ќе се доградува нов објект до оној на постојната локација и ќе бидат потребни околу 6 милиони евра. И таму најпрво е потребно проектирање, за што во тек е постапка за јавна набавка и во моментов се евалуираат пристигнатите 7 понуди. Потоа ќе следува избор на изведувач на градежни работи. Активностите на терен очекуваме да започнат во последниот квартал на тековната година - ни рекоа од МОН. Потребите, како и стандардите за градење, во меѓувреме, односно од 2013 кога почна изградбата, се сменети и затоа е одлучено, и наведено во тендерот, двата објекта да ги користи само Факултетот за информатички технологии и компјутерско инженерство (ФИНКИ) бидејќи само една зграда не ги задоволува потребите ниту на овој факултет ниту на Факултетот за физичко образование, спорт и здравје, за кој беше наменет другиот објект. Инаку, двата објекта, кои се простираат на вкупно 22.753 квадратни метри, ќе го задржат постојниот габарит и ќе немаат барокна фасада. Во нивната внатрешност, меѓу другото, ќе има ново распоредување на просториите, ќе има промени во инсталациите за греење и промени на компјутерската инсталација. Динамиката со која ќе продолжи изградбата на објектите ќе зависи од расположливите средства во буџетот. Кога МОН, УКИМ, Градежниот факултет и Службата за општи и заеднички работи при Владата (СОЗР) лани во мај го потпишаа меморандумот за формирање на работната група за увид во физичката состојба на објектите, беше соопштено дека според договорите за реализација на проектите од пред десетина години, изградбата на ФИНКИ требало да чини 784 милиони денари, а градењето на Факултетот за физичко образование, спорт и здравје требало да чини 432 милиони денари.";
         String cleaned = original.replaceAll("[^\\p{L}]", "").toUpperCase();
         String result = substituteLetters(cleaned, mappings);
         System.out.println("Original : " + original);
         System.out.println("Cleaned  : " + cleaned);
         System.out.println("Result   : " + result);
     }
 }